// 'topla' adlı funksiya yaradıram
function topla(a, b) {
  return a + b;
}

// Funksiyanı çağırıram
console.log(topla(2, 3)); // nəticə: 5

// 'salamVer' adlı funksiya yaradıram
function salamVer(ad) {
  return 'Salam, ' + ad + '!';
}

// Funksiyanı çağırıram
console.log(salamVer('Murad')); // nəticə: Salam, Murad!

// 'kofeHazirla' funksiyası iki parametr alır: kofe növü və şəkər
function kofeHazirla(kofeNövü, şəkər) {
  return 'Sənin ' + kofeNövü + ' kofen hazırdır, ' + şəkər + '!';
}

// Funksiyanı çağıranda arqumentlər verirəm: 'latte' və 'şəkərsiz'
console.log(kofeHazirla('latte', 'şəkərsiz')); // nəticə: Sənin latte kofen hazırdır, şəkərsiz!

// 'cix' adlı funksiya yaradıram
function cix(a, b) {
  return a - b;
}

// Funksiyanı çağırıram
console.log(cix(10, 3)); // nəticə: 7

// 'vur' adlı funksiyanı dəyişənə qoyuram
const vur = function(a, b) {
  return a * b;
};

// Funksiyanı çağırıram
console.log(vur(4, 5)); // nəticə: 20

// 'bol' adlı funksiyanı ox ilə yaradıram
const bol = (a, b) => {
  return a / b;
};

// Funksiyanı çağırıram
console.log(bol(10, 2)); // nəticə: 5

// Üçünü də müqayisə edək

// Function Declaration
function topla(a, b) {
  return a + b;
}
console.log(topla(2, 3)); // nəticə: 5

// Function Expression
const vur = function(a, b) {
  return a * b;
};
console.log(vur(4, 5)); // nəticə: 20

// Arrow Function
const bol = (a, b) => {
  return a / b;
};
console.log(bol(10, 2)); // nəticə: 5

